import{_ as o,o as t,c as r,ag as a}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"第4章 Docker 运行时后端","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/04-docker-runtime.md","filePath":"chapters/04-docker-runtime.md"}'),i={name:"chapters/04-docker-runtime.md"};function s(n,e,c,d,p,l){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="第4章-docker-运行时后端" tabindex="-1">第4章 Docker 运行时后端 <a class="header-anchor" href="#第4章-docker-运行时后端" aria-label="Permalink to &quot;第4章 Docker 运行时后端&quot;">​</a></h1><blockquote><p>&quot;Complexity is not the enemy — unmanaged complexity is. A 2000-line file that tells a coherent story is better than 20 files that tell none.&quot; — 改编自 Rich Hickey</p></blockquote><h2 id="为什么从-docker-后端读起" tabindex="-1">为什么从 Docker 后端读起 <a class="header-anchor" href="#为什么从-docker-后端读起" aria-label="Permalink to &quot;为什么从 Docker 后端读起&quot;">​</a></h2><p><code>server/src/services/docker.py</code> 是 OpenSandbox 中最大的单文件，约 2132 行代码。在上一章中我们提到，Docker 后端用一个文件封装了全部逻辑，而 Kubernetes 后端则拆分为 15 个文件。这并非疏忽 — Docker API 的抽象层级较低，容器创建、网络配置、卷管理和安全设置都在同一个 API 调用中完成，将这些紧密关联的逻辑放在一个文件中反而降低了认知负担。</p><h2 id="类继承结构" tabindex="-1">类继承结构 <a class="header-anchor" href="#类继承结构" aria-label="Permalink to &quot;类继承结构&quot;">​</a></h2><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> DockerSandboxService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">OSSFSMixin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SandboxService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">):</span></span></code></pre></div><p><code>DockerSandboxService</code> 通过多重继承组合了两个能力：<code>SandboxService</code> 抽象基类定义了生命周期接口（create、delete、pause、resume、get、list、renew），<code>OSSFSMixin</code> 则混入了 OSSFS（阿里云 OSS 文件系统）卷管理的 14 个方法。</p><p>为什么用 Mixin 而非组合模式？OSSFS 操作需要直接访问 Docker API client 和容器状态，如果封装为独立组件需要大量的上下文传递。Mixin 使得 OSSFS 方法可以直接访问 <code>self._docker_client</code> 和 <code>self._sandbox_expirations</code>，减少了胶水代码。</p><h2 id="初始化流程" tabindex="-1">初始化流程 <a class="header-anchor" href="#初始化流程" aria-label="Permalink to &quot;初始化流程&quot;">​</a></h2><p><code>__init__</code> 方法执行四个关键步骤：</p><ol><li><strong>Docker 客户端初始化</strong> — 调用 <code>docker.from_env()</code> 从环境变量（<code>DOCKER_HOST</code>、<code>DOCKER_TLS_CERTDIR</code>）创建客户端，API 超时默认 180 秒</li><li><strong>运行时类型验证</strong> — 确认配置的运行时类型为 <code>&quot;docker&quot;</code>，否则直接抛出异常</li><li><strong>状态管理器初始化</strong> — 创建线程安全的 <code>_sandbox_expirations</code> 字典和 <code>_expiration_timers</code> 计时器映射</li><li><strong>容器状态恢复</strong> — <code>_restore_existing_sandboxes()</code> 在服务重启时扫描所有现存容器，重建过期计时器和 OSSFS 引用计数</li></ol><p>状态恢复是容错设计的关键。如果 Lifecycle Server 崩溃重启，它不能丢失正在运行的沙盒的过期信息。恢复逻辑会先累积所有容器的 OSSFS 挂载引用计数，再启动过期计时器，避免在恢复过程中误删共享挂载。</p><h2 id="容器创建九步流程" tabindex="-1">容器创建九步流程 <a class="header-anchor" href="#容器创建九步流程" aria-label="Permalink to &quot;容器创建九步流程&quot;">​</a></h2><p><code>create_sandbox()</code> 和内部的 <code>_provision_sandbox()</code> 方法实现了一个精心编排的九步创建流程：</p><p><strong>第一步：输入验证</strong>。校验 entrypoint、metadata、超时时间、网络策略和卷配置。元数据过滤使用严格的键值对校验，拒绝格式错误的输入。</p><p><strong>第二步：上下文准备</strong>。生成沙盒 ID、记录创建时间戳、计算过期时间。沙盒被加入 <code>_pending_sandboxes</code> 字典追踪创建中状态。</p><p><strong>第三步：镜像拉取</strong>。支持 <code>ImageAuth</code> 认证的私有镜像拉取。execd 镜像使用内存缓存的 tar 归档，避免每次创建都重新读取磁盘。</p><p><strong>第四步：资源分配</strong>。解析内存限制（字节）和 CPU 份额（nano 单位），为 execd 端口（44772）和 HTTP 端口（8080）分配宿主机端口。</p><p><strong>第五步：卷配置</strong>。处理三种卷后端 — Host（直接绑定挂载）、PVC（Docker 命名卷）、OSSFS（S3 桶挂载）。每种后端有独立的验证逻辑，包括符号链接攻击防护。</p><p><strong>第六步：Sidecar 创建</strong>。如果配置了网络策略，在 bridge 网络上启动 egress sidecar 容器。</p><p><strong>第七步：容器创建与启动</strong>。构建包含安全选项的 host config，创建并启动容器。</p><p><strong>第八步：运行时注入</strong>。将 execd 二进制文件和 bootstrap 脚本通过 <code>put_archive</code> API 注入容器。bootstrap 脚本包装了用户的原始 entrypoint，确保 execd 在容器启动时就开始运行。</p><p><strong>第九步：过期调度</strong>。注册守护线程计时器，到期自动调用 <code>_expire_sandbox()</code> 销毁沙盒。</p><h2 id="安全纵深配置" tabindex="-1">安全纵深配置 <a class="header-anchor" href="#安全纵深配置" aria-label="Permalink to &quot;安全纵深配置&quot;">​</a></h2><p>Docker 后端实现了多层安全加固，这些配置分布在 <code>_create_and_start_container()</code> 方法中：</p><p><strong>Capability 管理</strong>。默认丢弃 9 项 Linux capabilities，当存在网络策略时额外丢弃 <code>NET_ADMIN</code>。这遵循最小权限原则 — 沙盒中的代码不需要修改网络接口或加载内核模块的能力。</p><p><strong>权限限制</strong>。启用 <code>no_new_privileges=True</code>，防止沙盒中的进程通过 setuid/setgid 提升权限。这一行配置阻断了大量提权攻击路径。</p><p><strong>安全配置文件</strong>。支持 AppArmor profile 和 Seccomp profile 注入，进一步限制系统调用范围。</p><p><strong>进程数限制</strong>。<code>pids_limit=512</code> 防止 fork bomb 攻击耗尽系统资源。</p><p><strong>安全运行时</strong>。通过 <code>SecureRuntimeResolver</code> 支持 gVisor（runsc）和 Kata Containers，在容器层面提供内核级隔离。</p><h2 id="状态管理-线程安全的过期机制" tabindex="-1">状态管理：线程安全的过期机制 <a class="header-anchor" href="#状态管理-线程安全的过期机制" aria-label="Permalink to &quot;状态管理：线程安全的过期机制&quot;">​</a></h2><p>沙盒的生命周期管理依赖三个线程安全的数据结构：</p><ul><li><code>_sandbox_expirations: Dict[str, float]</code> — 记录每个沙盒的过期时间戳</li><li><code>_expiration_timers: Dict[str, Timer]</code> — 维护守护线程计时器</li><li><code>_pending_sandboxes: Dict[str, SandboxInfo]</code> — 追踪创建中的沙盒</li></ul><p><code>_schedule_expiration()</code> 方法在创建和续期时调用，它会取消现有计时器并创建新计时器，保证幂等性。计时器使用守护线程，当主进程退出时自动终止，不会导致僵尸线程。</p><p>创建失败的沙盒会被标记为 <code>Failed</code> 状态并保留在 <code>_pending_sandboxes</code> 中，通过 <code>_pending_cleanup_timers</code> 在 TTL（默认 3600 秒）后自动清理。这个设计允许客户端在创建失败后仍能查询到错误信息，而不是直接消失。</p><h2 id="网络模式" tabindex="-1">网络模式 <a class="header-anchor" href="#网络模式" aria-label="Permalink to &quot;网络模式&quot;">​</a></h2><p>Docker 后端支持两种网络模式：</p><p><strong>Host 模式</strong>：容器直接共享宿主机网络栈，无端口映射开销。但不支持网络策略（因为无法为单个容器配置独立的出口规则）。端点地址为 <code>127.0.0.1:port</code>。</p><p><strong>Bridge 模式</strong>（默认）：容器通过端口映射暴露服务。支持网络策略 — egress sidecar 与主容器共享同一 bridge 网络，拦截出站流量。端口映射信息存储在容器标签中，便于重启后恢复。</p><p>当配置了网络策略时，系统强制使用 bridge 模式，因为 host 模式下 sidecar 无法有效隔离流量。</p><h2 id="ossfsmixin-引用计数的卷管理" tabindex="-1">OSSFSMixin：引用计数的卷管理 <a class="header-anchor" href="#ossfsmixin-引用计数的卷管理" aria-label="Permalink to &quot;OSSFSMixin：引用计数的卷管理&quot;">​</a></h2><p><code>OSSFSMixin</code> 提供了 14 个方法管理 OSSFS 卷，核心挑战是 <strong>共享挂载的生命周期管理</strong>。多个沙盒可能挂载同一个 OSS 桶路径，直接卸载会影响其他沙盒。</p><p>解决方案是 <strong>引用计数</strong>。每次挂载时增加计数，每次释放时减少计数，只有当计数归零时才真正执行卸载操作。<code>_release_ossfs_mounts()</code> 方法在沙盒销毁时调用，确保计数安全递减。</p><p>Mixin 同时支持 OSSFS v1.0 和 v2.0 两个版本，提供 30 秒超时和失败回滚机制，以及注入攻击防护（验证路径参数不包含恶意字符）。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>Docker 后端通过一个约 2132 行的文件实现了完整的沙盒生命周期管理，包括九步容器创建流程、多层安全加固、线程安全的过期机制和引用计数的 OSSFS 卷管理。其设计处处体现了对安全性和容错性的重视 — 从 9 项 capability 丢弃到 <code>no_new_privileges</code> 限制，从状态恢复到失败沙盒的延迟清理。在下一章中，我们将看到 Kubernetes 后端如何用一套完全不同的抽象解决同样的问题。</p>',46)])])}const _=o(i,[["render",s]]);export{g as __pageData,_ as default};
